const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 8);
const tool_call_id = `tc_drive_${timestamp}_${random}`;

const body = $json.body || {};
const operation = body.operation || $json.operation || 'unknown';

return {
  json: {
    ...($json.body ? { body: $json.body } : $json),
    tool_call_id,
    session_id: body.session_id || $json.session_id || 'unknown',
    intent_id: body.intent_id || $json.intent_id || null,
    callback_url: body.callback_url || $json.callback_url || null,
    operation,
    parameters: body,
    start_time: timestamp
  }
};

