INSERT INTO tool_calls (
  tool_call_id, session_id, intent_id, function_name, 
  parameters, status, callback_url, created_at
) VALUES (
  $1, $2, $3, $4, $5, 'EXECUTING', $6, NOW()
)
RETURNING id, tool_call_id;

