// Handle both success and error cases
const input = $input.all();

// Check if this is an error response (from onError: continueRegularOutput)
if (input.length === 0 || (input[0].json && input[0].json.error)) {
  const errorMsg = input[0]?.json?.error?.message || input[0]?.json?.message || 'Drive temporarily unavailable';
  return [{ json: { error: true, message: errorMsg, files: [], count: 0 } }];
}

// Normal success path
const files = input.map(item => ({
  id: item.json.id,
  name: item.json.name,
  mimeType: item.json.mimeType,
  size: item.json.size,
  modifiedTime: item.json.modifiedTime,
  webViewLink: item.json.webViewLink
}));

return [{ json: { files, count: files.length } }];

const downloadNodeData = $input.first()?.json || {};

// Check if this is an error response (from onError: continueRegularOutput)
if (downloadNodeData.error || (!downloadNodeData.id && !downloadNodeData.text && !downloadNodeData.data)) {
  const errorMsg = downloadNodeData.error?.message || downloadNodeData.message || 'Extraction failed';
  return [{
    json: {
      drive_file_id: 'error',
      drive_folder_id: '11KcezPe3NqgcC3TNvHxAAZS4nPYrMXRF',
      file_name: 'error',
      mime_type: 'error',
      file_size_bytes: 0,
      web_view_link: '',
      extracted_text: errorMsg,
      text_length: 0,
      extraction_method: 'error',
      drive_modified_time: null,
      extraction_status: 'FAILED'
    }
  }];
}

const extractedText = downloadNodeData.text || downloadNodeData.data || '';

// Safely extract file metadata - handle both Google Drive fields and PDF metadata contamination
const fileId = downloadNodeData.id || 'unknown';
const fileName = downloadNodeData.name || 'unknown';
const mimeType = downloadNodeData.mimeType || 'application/octet-stream';
const webViewLink = downloadNodeData.webViewLink || '';
const modifiedTime = downloadNodeData.modifiedTime || null;

// Safely parse numeric fields - protect against non-numeric strings
const rawSize = downloadNodeData.size;
const fileSize = (typeof rawSize === 'number') ? rawSize : 
                 (typeof rawSize === 'string' && /^\d+$/.test(rawSize)) ? parseInt(rawSize, 10) : 0;

const textLength = typeof extractedText === 'string' ? extractedText.length : 0;

return [{
  json: {
    drive_file_id: fileId,
    drive_folder_id: '11KcezPe3NqgcC3TNvHxAAZS4nPYrMXRF',
    file_name: fileName,
    mime_type: mimeType,
    file_size_bytes: fileSize,
    web_view_link: webViewLink,
    extracted_text: extractedText,
    text_length: textLength,
    extraction_method: 'auto',
    drive_modified_time: modifiedTime,
    extraction_status: 'SUCCESS'
  }
}];

return [{
  json: {
    error: 'Invalid operation',
    message: 'Operation must be one of: list, search, sync, get, analyze',
    available_operations: ['list', 'search', 'sync', 'get', 'analyze']
  }
}];

// Handle search results including empty case
const input = $input.all();
const toolCallId = $('Generate Tool Call ID').first().json.tool_call_id;
const sessionId = $('Generate Tool Call ID').first().json.session_id;
const intentId = $('Generate Tool Call ID').first().json.intent_id;
const params = $('Generate Tool Call ID').first().json.parameters;

// Check if we have results
if (!input || input.length === 0 || (input[0].json && input[0].json.error)) {
  return [{
    json: {
      tool_call_id: toolCallId,
      session_id: sessionId,
      intent_id: intentId,
      parameters: params,
      results: [],
      count: 0,
      message: 'No matching documents found'
    }
  }];
}

// Format results
const results = input.map(item => ({
  id: item.json.id,
  file_name: item.json.file_name,
  mime_type: item.json.mime_type,
  web_view_link: item.json.web_view_link,
  extracted_text: item.json.extracted_text?.substring(0, 500),
  relevance_score: item.json.relevance_score
}));

return [{
  json: {
    tool_call_id: toolCallId,
    session_id: sessionId,
    intent_id: intentId,
    parameters: params,
    results: results,
    count: results.length
  }
}];

